/* global React, Icon, Logo, Stat, StepDot */
// Vitrine — homepage ANB Corporate

const DIRECTOR_PHOTO = "data:image/webp;base64,";

const useCopy = () => {
  const [c, setC] = React.useState(window.__pas_copy || {});
  React.useEffect(() => {
    const h = () => setC({ ...window.__pas_copy });
    window.addEventListener('pas-copy-update', h);
    return () => window.removeEventListener('pas-copy-update', h);
  }, []);
  return {
    ctaLabel: c.ctaLabel || 'Créer mon entreprise',
    heroBadge: c.heroBadge || "Cabinet certifié · Cocody, Abidjan 🇨🇮",
    brandName: c.brandName || 'ANB Corporate',
    headline: c.headline || 'Créez votre entreprise en',
    cabinetName: c.cabinetName || 'ANB Corporate',
    cabinetCity: c.cabinetCity || 'Cocody, Abidjan',
    cabinetEmail: c.cabinetEmail || 'info@anbcorporate.com',
    cabinetPhone: c.cabinetPhone || '+225 07 87 44 88 57',
  };
};

const VitrineNav = ({ light = false }) => {
  const nav = useNav();
  const links = [
    { l: 'Services', p: '/#services' },
    { l: 'Tarifs', p: '/tarifs' },
    { l: 'À propos', p: '/apropos' },
    { l: 'FAQ', p: '/faq' },
    { l: 'Contact', p: '/contact' },
  ];
  return (
  <div data-vitrine-nav style={{
    display: 'flex', alignItems: 'center', justifyContent: 'space-between',
    padding: '20px 56px',
    color: light ? 'white' : 'var(--ink-900)',
  }}>
    <span onClick={() => nav('/')} style={{ cursor: 'pointer' }}><Logo light={light} /></span>
    <div data-vitrine-menu style={{ display: 'flex', gap: 28, font: '500 14px/1 var(--font-body)' }}>
      {links.map((s) => (
        <span key={s.l} onClick={() => nav(s.p)} style={{ opacity: light ? 0.85 : 0.75, cursor: 'pointer' }}>{s.l}</span>
      ))}
    </div>
    <div data-vitrine-actions style={{ display: 'flex', gap: 10 }}>
      <button onClick={() => nav('/partenaire/dashboard')} className="btn btn-sm" style={{ background: 'transparent', color: light ? 'white' : 'var(--ink-900)', border: `1px solid ${light ? 'rgba(255,255,255,.25)' : 'var(--ink-200)'}` }}>Connexion</button>
      <button onClick={() => nav('/quiz')} className="btn btn-sm" style={{ background: light ? 'white' : 'var(--ink-900)', color: light ? 'var(--ink-900)' : 'white' }}>
        Créer mon entreprise <Icon name="arrow" size={14} />
      </button>
    </div>
  </div>
  );
};

